import json
import pandas as pd

reviews = var_call_ECBqnbMiXYF7hhX4AdoVUM13
books_file_path = var_call_ZFYRrX85nXfIDGYu6KWmVNOM

with open(books_file_path, 'r', encoding='utf-8') as f:
    books = json.load(f)

# Map purchaseid_ to bookid_
purchase_ids = [r.get('purchase_id') for r in reviews]
mapped_ids = []
for pid in purchase_ids:
    if isinstance(pid, str) and pid.startswith('purchaseid_'):
        mapped_ids.append(pid.replace('purchaseid_', 'bookid_'))
    else:
        mapped_ids.append(pid)
mapped_set = set(mapped_ids)

# Build lookup by book_id
book_lookup = {b.get('book_id'): b for b in books}

# helper to detect english
def looks_english(text):
    if not text:
        return False
    txt = text.lower()
    if 'english' in txt:
        return True
    # simple heuristic: presence of common english words
    common = [' the ', ' and ', ' of ', ' to ', ' in ', ' a ']
    hits = sum(1 for w in common if w in (' ' + txt + ' '))
    return hits >= 2

results = []
for bid in mapped_set:
    book = book_lookup.get(bid)
    if not book:
        continue
    cats = book.get('categories') or ''
    if not isinstance(cats, str):
        try:
            cats = json.dumps(cats)
        except Exception:
            cats = str(cats)
    if 'literature & fiction' not in cats.lower():
        continue
    # check english in several fields
    combined = ''
    for key in ['description', 'details', 'author', 'title', 'categories']:
        val = book.get(key)
        if not val:
            continue
        if not isinstance(val, str):
            try:
                val = json.dumps(val)
            except Exception:
                val = str(val)
        combined += ' ' + val
    if looks_english(combined):
        results.append({'book_id': book.get('book_id'), 'title': book.get('title'), 'author': book.get('author'), 'categories': book.get('categories')})

# As JSON string
out = json.dumps(results)
print("__RESULT__:")
print(out)

