import json
# Read the execute_python output file that contains the matches
file_path = var_call_eDCE9v9elBzSwlETVoxOxNj7
with open(file_path, 'r', encoding='utf-8') as f:
    matches = json.load(f)

lines = []
for m in matches:
    title = m.get('title') or ''
    author_field = m.get('author')
    author_name = None
    if author_field and isinstance(author_field, str):
        # try to parse as json
        try:
            ad = json.loads(author_field)
            if isinstance(ad, dict):
                author_name = ad.get('name')
            else:
                author_name = str(ad)
        except Exception:
            if author_field.strip().lower() == 'none':
                author_name = None
            else:
                author_name = author_field
    else:
        author_name = author_field
    bid = m.get('book_id')
    if author_name:
        lines.append(f"{title} — {author_name} ({bid})")
    else:
        lines.append(f"{title} ({bid})")

if not lines:
    final_text = "No matching English-language books in 'Literature & Fiction' with average rating 5.0 were found."
else:
    final_text = "\n".join(lines)

print("__RESULT__:")
print(json.dumps(final_text))

